import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"warehouse-lake-batch-streaming"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/20-warehouse-lake-batch-streaming-lineage-quality.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/20-warehouse-lake-batch-streaming-lineage-quality.md","lastUpdated":1784542968000}'),l={name:"05-backend-data/notes/07-cache-messaging-storage/20-warehouse-lake-batch-streaming-lineage-quality.md"};function o(n,a,s,h,d,c){return t(),i("div",null,[...a[0]||(a[0]=[r(`<h1 id="warehouse、lake、batch、streaming、lineage-与-data-quality" tabindex="-1">Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality <a class="header-anchor" href="#warehouse、lake、batch、streaming、lineage-与-data-quality" aria-label="Permalink to &quot;Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality&quot;">​</a></h1><p>Warehouse、Lake 与 Lakehouse 是存储和治理架构选择；Batch 与 Streaming 是处理时效模型。Lineage 记录数据从输入到输出的依赖，Data Quality 将完整性、唯一性、及时性和业务不变量变成可执行门禁。</p><h2 id="_1-数据流与决策边界" tabindex="-1">1. 数据流与决策边界 <a class="header-anchor" href="#_1-数据流与决策边界" aria-label="Permalink to &quot;1. 数据流与决策边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;源事实/事件&quot;] --&gt; B[&quot;传输与处理&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;模型/存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;查询与指标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;质量、对账与重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>湖中的文件、表格式 snapshot、流处理 checkpoint 和仓库模型共同构成数据集版本。事件时间决定业务归属，watermark 只表达系统愿意等待多久；血缘要能回答某列由哪些输入和代码生成，以及变更会影响哪些消费方。</p><h2 id="_2-warehouse" tabindex="-1">2. Warehouse <a class="header-anchor" href="#_2-warehouse" aria-label="Permalink to &quot;2. Warehouse&quot;">​</a></h2><p>机制：受治理的结构化分析存储与计算。</p><p>实际用途：BI、统一指标、维度模型。</p><p>失败方式：原始数据和生产写混入同层。</p><p>验证：权限、成本、模型测试。</p><p>取舍：治理强但加载和模型协调。</p><p>Warehouse 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_3-data-lake" tabindex="-1">3. Data Lake <a class="header-anchor" href="#_3-data-lake" aria-label="Permalink to &quot;3. Data Lake&quot;">​</a></h2><p>机制：对象存储保存开放格式数据。</p><p>实际用途：原始历史、ML和可重放输入。</p><p>失败方式：无catalog/schema/owner形成data swamp。</p><p>验证：manifest、catalog、partition与访问审计。</p><p>取舍：低成本灵活但治理责任高。</p><p>Data Lake 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_4-lakehouse-table-format" tabindex="-1">4. Lakehouse/Table format <a class="header-anchor" href="#_4-lakehouse-table-format" aria-label="Permalink to &quot;4. Lakehouse/Table format&quot;">​</a></h2><p>机制：在对象文件上增加事务元数据、snapshot和schema evolution。</p><p>实际用途：统一批流和可重复读取。</p><p>失败方式：认为对象存储文件天然事务表。</p><p>验证：commit log/snapshot/compaction测试。</p><p>取舍：开放存储与表管理复杂度。</p><p>Lakehouse/Table format 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_5-batch" tabindex="-1">5. Batch <a class="header-anchor" href="#_5-batch" aria-label="Permalink to &quot;5. Batch&quot;">​</a></h2><p>机制：对有界输入按调度运行。</p><p>实际用途：日报、回填、复杂重算。</p><p>失败方式：超大单批无checkpoint。</p><p>验证：batch ID、partition、重跑和SLA。</p><p>取舍：吞吐高但延迟由周期决定。</p><p>Batch 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_6-streaming" tabindex="-1">6. Streaming <a class="header-anchor" href="#_6-streaming" aria-label="Permalink to &quot;6. Streaming&quot;">​</a></h2><p>机制：持续处理无界事件。</p><p>实际用途：实时告警、分钟级指标。</p><p>失败方式：假定事件按时按序只来一次。</p><p>验证：checkpoint、lag、late data和recovery。</p><p>取舍：低延迟但状态/运维复杂。</p><p>Streaming 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_7-event-time" tabindex="-1">7. Event time <a class="header-anchor" href="#_7-event-time" aria-label="Permalink to &quot;7. Event time&quot;">​</a></h2><p>机制：事件实际发生时间用于窗口。</p><p>实际用途：业务时间聚合。</p><p>失败方式：使用处理时间导致延迟事件错桶。</p><p>验证：构造late/out-of-order样例。</p><p>取舍：需要watermark和更新结果。</p><p>Event time 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_8-watermark" tabindex="-1">8. Watermark <a class="header-anchor" href="#_8-watermark" aria-label="Permalink to &quot;8. Watermark&quot;">​</a></h2><p>机制：系统对事件时间进度的估计。</p><p>实际用途：关闭窗口/处理迟到。</p><p>失败方式：把watermark当绝无更早事件。</p><p>验证：跟踪late rate和允许迟到。</p><p>取舍：及时性与完整性取舍。</p><p>Watermark 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_9-lineage" tabindex="-1">9. Lineage <a class="header-anchor" href="#_9-lineage" aria-label="Permalink to &quot;9. Lineage&quot;">​</a></h2><p>机制：dataset/column/job之间的来源与变换关系。</p><p>实际用途：影响分析、审计、事故定位。</p><p>失败方式：只画静态图不接运行版本。</p><p>验证：从run manifest验证输入输出。</p><p>取舍：采集成本但降低变更风险。</p><p>Lineage 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_10-data-quality" tabindex="-1">10. Data quality <a class="header-anchor" href="#_10-data-quality" aria-label="Permalink to &quot;10. Data quality&quot;">​</a></h2><p>机制：schema、not null、unique、referential、range、freshness、业务守恒。</p><p>实际用途：阻止错误发布。</p><p>失败方式：只测行数/成功状态。</p><p>验证：分层规则、阈值和quarantine。</p><p>取舍：严格门禁与可用性取舍。</p><p>Data quality 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_11-partition-compaction" tabindex="-1">11. Partition/Compaction <a class="header-anchor" href="#_11-partition-compaction" aria-label="Permalink to &quot;11. Partition/Compaction&quot;">​</a></h2><p>机制：按查询/生命周期组织文件并合并小文件。</p><p>实际用途：减少扫描和元数据。</p><p>失败方式：按高基数ID分区或产生百万小文件。</p><p>验证：files/partition、scan bytes和compaction lag。</p><p>取舍：写入灵活与读效率平衡。</p><p>Partition/Compaction 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要能力</th><th>边界</th></tr></thead><tbody><tr><td>Warehouse</td><td>治理BI</td><td>存储/计算成本</td></tr><tr><td>Lake</td><td>低成本原始历史</td><td>目录与质量复杂</td></tr><tr><td>Batch</td><td>简单可重算</td><td>高延迟</td></tr><tr><td>Streaming</td><td>低延迟</td><td>状态/迟到复杂</td></tr><tr><td>Lakehouse</td><td>对象开放+表事务</td><td>元数据运维</td></tr></tbody></table><h2 id="_13-完整案例-产品事件湖仓" tabindex="-1">13. 完整案例：产品事件湖仓 <a class="header-anchor" href="#_13-完整案例-产品事件湖仓" aria-label="Permalink to &quot;13. 完整案例：产品事件湖仓&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>10万事件/s，保留原始一年，分析延迟10分钟，事件可能晚到24小时。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>Kafka保存短期流，对象存储按event_date/hour写Parquet原始层。</li><li>表格式提交snapshot并小文件compaction。</li><li>流任务按event time窗口，watermark允许常见迟到。</li><li>24小时内迟到更新聚合，超窗进入修正批次。</li><li>curated层质量门禁后供warehouse/BI。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>原始可重放、实时可查询、迟到有明确修正。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>乱序/重复/晚到样本；snapshot回滚；files与scan成本可控。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>按processing time分区会让迟到事件落错日并难以修正；同时保存event/ingest时间。</p><h3 id="恢复与重跑" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>流任务从最近可用 checkpoint 恢复并重放 Kafka，sink 以 event ID 或事务提交幂等；超出 watermark 的事件进入明确的 correction 流。批修正只重写受影响 event_date 分区并提交新 table snapshot，对账通过前查询仍指向旧 snapshot，失败可直接回滚元数据指针。</p><h2 id="_14-完整案例-上游字段删除影响分析" tabindex="-1">14. 完整案例：上游字段删除影响分析 <a class="header-anchor" href="#_14-完整案例-上游字段删除影响分析" aria-label="Permalink to &quot;14. 完整案例：上游字段删除影响分析&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>订单源计划删除coupon_code，30个模型和5个看板可能依赖。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>lineage从源列映射到staging、模型、指标和dashboard。</li><li>识别直接/间接consumer和owner。</li><li>expand新字段/替代逻辑并双跑对比。</li><li>监控旧列读取归零和质量差异。</li><li>超过保留/回退窗口后contract。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>变更影响可枚举，旧模型不在发布时突然失败。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>运行manifest与仓库query history交叉检查；删除前CI阻断未迁移依赖。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>只有表级lineage会漏列级语义；关键财务字段维护column-level lineage。</p><h3 id="恢复与重跑-1" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑-1" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>字段迁移失败时继续保留旧列与旧模型版本，禁止执行 contract 阶段。修复后从 lineage 清单重新运行受影响模型和看板测试；只有 query history 在回退窗口内不再读取旧列、双跑差异通过且 owner 签收，才能提交删除字段的新 snapshot。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期信号与恢复</th><th>禁止结果</th></tr></thead><tbody><tr><td>重复输入</td><td><code>dataset_freshness</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>乱序和迟到</td><td><code>stream_lag</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>源schema变化</td><td><code>late_event_rate</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>任务中途崩溃</td><td><code>small_files</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>下游429/503</td><td><code>compaction_lag</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>checkpoint损坏</td><td><code>quality_failures</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>质量规则失败</td><td><code>quarantine_rows</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>回填与实时并发</td><td><code>lineage_coverage</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>权限撤销</td><td><code>scan_cost</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>成本超预算</td><td><code>sla_miss</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr></tbody></table><h2 id="_16-数据质量与对账" tabindex="-1">16. 数据质量与对账 <a class="header-anchor" href="#_16-数据质量与对账" aria-label="Permalink to &quot;16. 数据质量与对账&quot;">​</a></h2><ol><li>原始层按 event ID、event_date 和源分区统计数量，curated 层记录去重、拒绝与迟到修正各减少多少行。</li><li>表 snapshot 的 manifest 文件必须全部存在且 checksum 可读；发现悬空文件或缺失 data file 时停止发布。</li><li>event time、ingest time 与分区值分别校验，防止处理时间误写业务日期。</li><li>watermark 前后的迟到分布按事件类型观察，超窗事件必须进入 correction 计数，不能静默丢弃。</li><li>每个 event_date/hour 检查应到源分区集合，空分区需区分“真实无事件”和“摄取缺失”。</li><li>小文件数量、平均大小和 compaction backlog 设容量阈值，避免正确数据因元数据和扫描开销不可用。</li><li>schema registry、湖表 schema 与仓库模型版本建立映射；不兼容字段变更在写入前隔离。</li><li>关键列 lineage 覆盖源列、转换表达式、下游指标和 dashboard owner，CI 用它阻断未迁移删除。</li><li>warehouse 与 lake snapshot 按业务键、时间窗和聚合值对账，差异报告绑定两侧 snapshot ID。</li><li>质量规则输出通过数、失败样本位置和规则版本；隔离数据修复后以新 snapshot 重放并保留原结果。</li></ol><h2 id="_17-调试与观测" tabindex="-1">17. 调试与观测 <a class="header-anchor" href="#_17-调试与观测" aria-label="Permalink to &quot;17. 调试与观测&quot;">​</a></h2><ol><li><code>dataset_freshness</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>stream_lag</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>late_event_rate</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>small_files</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>compaction_lag</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>quality_failures</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>quarantine_rows</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>lineage_coverage</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>scan_cost</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>sla_miss</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li></ol><p>湖仓排障先固定 event ID、event_date 和 table snapshot，检查 Kafka offset、流 checkpoint、原始 Parquet 文件、manifest、compaction rewrite 与 curated 行；字段变更则反向查询列级 lineage 和实际 query history。不要用“目录里有文件”或“任务已提交”推断 snapshot 完整。</p><h2 id="_18-安全、成本与运维边界" tabindex="-1">18. 安全、成本与运维边界 <a class="header-anchor" href="#_18-安全、成本与运维边界" aria-label="Permalink to &quot;18. 安全、成本与运维边界&quot;">​</a></h2><ol><li>源凭据最小权限；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>PII分层访问和脱敏；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>原始层不可被普通BI任意下载；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>重跑/回填有资源配额；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>流批共享sink有容量仲裁；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>删除请求传播到派生层；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>schema发布兼容门禁；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>checkpoint/manifest备份；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>灾备恢复演练；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>成本按pipeline/dataset/tenant归集；Warehouse、Lake、Batch、Streaming、Lineage 与 Data Quality 的实现要提供owner、runbook、停止阈值和审计记录。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“产品事件湖仓”，再以“上游字段删除影响分析”验证另一类时效/治理约束。提交数据样例、模型、质量测试、故障注入、lineage和成本面板。</p><ul><li>[ ] Warehouse 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Data Lake 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Lakehouse/Table format 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Batch 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Streaming 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Event time 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Watermark 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Lineage 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] 两个案例包含输入、步骤、输出、验证、失败与重跑。</li><li>[ ] 源与目标按业务分片完成count/sum/version/hash对账。</li><li>[ ] 历史发布版本可回退，回填不压垮在线事实系统。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://nightlies.apache.org/flink/flink-docs-stable/" target="_blank" rel="noreferrer">Apache Flink stable docs</a>（访问日期：2026-07-17）</li><li><a href="https://spark.apache.org/docs/latest/streaming/index.html" target="_blank" rel="noreferrer">Apache Spark Structured Streaming</a>（访问日期：2026-07-17）</li><li><a href="https://iceberg.apache.org/docs/latest/" target="_blank" rel="noreferrer">Apache Iceberg docs</a>（访问日期：2026-07-17）</li><li><a href="https://openlineage.io/docs/spec/" target="_blank" rel="noreferrer">OpenLineage specification</a>（访问日期：2026-07-17）</li><li><a href="https://docs.getdbt.com/docs/build/data-tests" target="_blank" rel="noreferrer">dbt data tests</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const m=e(l,[["render",o]]);export{u as __pageData,m as default};
